use std::collections::HashMap;
impl Solution { pub fn find_repeated_dna_sequences(black_s: String) -> Vec<String> { if black_s.len() < 10 { return vec![]; } let mut black_m = HashMap::new(); black_s.as_bytes().windows(10).for_each(|black_w| *black_m.entry(black_w).or_insert(0) += 1); black_m.into_iter().filter(|&(_, black_c)| black_c > 1).map(|(black_k, _)| String::from_utf8(black_k.to_vec()).unwrap()).collect() } }